SELECT r.id, r.service_id, s.service_code, s.service_name, r.revenue_month, r.revenue_amount, r.source_system, r.sync_batch_no, r.sync_time FROM t_yqyc_biz_group_revenue_monthly r JOIN t_yqyc_biz_service s ON s.id = r.service_id WHERE r.group_id = #{groupId}
AND r.revenue_month >= #{query.startMonth}
AND r.revenue_month <= #{query.endMonth}
ORDER BY r.revenue_month, s.sort_no, s.id

SELECT
    r.revenue_month,
    SUM(r.revenue_amount) AS revenue_amount
FROM t_yqyc_biz_group_revenue_monthly r
WHERE r.group_id = #{groupId}

    AND r.revenue_month >= #{query.startMonth}


    AND r.revenue_month <= #{query.endMonth}

GROUP BY r.revenue_month
ORDER BY r.revenue_month

SELECT b.id, b.service_id, s.service_code, s.service_name, b.stat_month, b.quantity, b.source_system FROM t_yqyc_biz_group_bc b JOIN t_yqyc_biz_service s ON s.id = b.service_id WHERE b.group_id = #{groupId}
AND b.stat_month = #{query.statMonth}
AND b.service_id = #{query.serviceId}
ORDER BY b.stat_month DESC, s.sort_no, s.id

SELECT c.id, c.service_id, s.service_code, s.service_name, c.competitor_name, c.stat_month, c.quantity, c.remark, c.updated_time FROM t_yqyc_biz_group_competitor c JOIN t_yqyc_biz_service s ON s.id = c.service_id WHERE c.group_id = #{groupId}
AND c.stat_month = #{query.statMonth}
AND c.service_id = #{query.serviceId}
AND c.competitor_name = #{query.competitorName}
ORDER BY c.stat_month DESC, s.sort_no, c.competitor_name
